module dff_en(
    input clk,
    input rst_n,
    input en,
    input d,
    output reg q
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            q <= 1'b0;
        end else if (en) begin
            q <= d;
        end
    end
endmodule
